Problem Statement

Maxim likes dividers of the numbers. Also Maxim is fond of **lucky numbers**&nbsp;

**lucky numbers****4****7****47****744****4****5****17****467**&nbsp;

**n****overlucky**&nbsp;

**overlucky****72344****2****3****744****223**&nbsp;

code.C:
#include <stdio.h>
#include <stdlib.h>

void genLucky(long long cur, long long limit, long long *arr, int *cnt) {
    if (cur > limit) return;
    if (cur != 0) arr[(*cnt)++] = cur;
    genLucky(cur * 10 + 4, limit, arr, cnt);
    genLucky(cur * 10 + 7, limit, arr, cnt);
}

int cmp(const void *a, const void *b) {
    long long x = *(const long long*)a, y = *(const long long*)b;
    return (x > y) - (x < y);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const long long LIM = 1000000000LL;
    long long lucky[2000];
    int luckyCnt = 0;
    genLucky(0, LIM, lucky, &luckyCnt);
    qsort(lucky, luckyCnt, sizeof(long long), cmp);
    while (T--) {
        long long n;
        scanf("%lld", &n);
        int ans = 0;
        for (int i = 0; i < luckyCnt && lucky[i] <= n; ++i) {
            if (n % lucky[i] == 0) ++ans;
        }
        printf("%d\n", ans);
    }
    return 0;
}

