}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    const long long LIM = 1'000'000'000LL;
    vector<long long> lucky;
    genLucky(0, LIM, lucky);
    sort(lucky.begin(), lucky.end());
    while (T--) {
        long long n; cin >> n;
        int ans = 0;
        for (long long x : lucky) {
            if (x > n) break;
            if (n % x == 0) ++ans;
        }
        cout << ans << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    static final long LIMIT = 1_000_000_000L;
    static List<Long> lucky = new ArrayList<>();

    static void genLucky(long cur) {
        if (cur > LIMIT) return;
        if (cur != 0) lucky.add(cur);
        genLucky(cur * 10 + 4);
        genLucky(cur * 10 + 7);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        genLucky(0);
        Collections.sort(lucky);
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; ++t) {
            long n = Long.parseLong(br.readLine().trim());
            int ans = 0;
            for (long x : lucky) {
                if (x > n) break;
                if (n % x == 0) ++ans;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def gen_lucky(limit):
    res = []
    def dfs(cur):
        if cur > limit:
            return
        if cur != 0:
            res.append(cur)
        dfs(cur * 10 + 4)
        dfs(cur * 10 + 7)
    dfs(0)
    res.sort()
    return res

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    lucky = gen_lucky(1_000_000_000)
    out = []
    for _ in range(T):
        n = int(next(it))
        cnt = 0
        for x in lucky:
            if x > n:
                break
            if n % x == 0:
                cnt += 1
        out.append(str(cnt))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

